+            .expect("lookup should succeed")
+            .expect("target group should exist");
+        assert_eq!(found.meta.group_id(), target_group_id);
+        assert_eq!(
+            found.repair_symbols.len(),
+            usize::try_from(found.meta.r_repair).expect("small r should fit usize")
+        );
+    });
 }
